#!/bin/bash
set -e
cd "$(dirname "$0")"
if [ ! -f backend/app.py ]; then
  echo "找不到 backend/app.py，請確認這個腳本放在 yt-app 資料夾裡再執行"
  exit 1
fi
cp backend/app.py backend/app.py.backup3
echo "已備份舊版到 backend/app.py.backup3"
echo "" | base64 -d > backend/app.py
echo "已寫入新版 backend/app.py"
if grep -q "debug-secret" backend/app.py; then
  echo "確認成功：有找到 debug-secret"
else
  echo "警告：沒找到，請把這行結果貼給Claude"
fi
